#include <stdio.h>

static void order_pair(int a, int b, int *minimum, int *maximum) {
    if (a <= b) { *minimum = a; *maximum = b; }
    else { *minimum = b; *maximum = a; }
}

int main(void) {
    int a, b, minimum, maximum;
    if (scanf("%d %d", &a, &b) != 2) return 1;
    order_pair(a, b, &minimum, &maximum);
    printf("%d %d\n", minimum, maximum);
    return 0;
}
